import{_ as t,o as r,c as a,a2 as e}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"储能赛道的投资逻辑：从\\"政策驱动\\"到\\"价值驱动\\"的拐点","description":"","frontmatter":{},"headers":[],"relativePath":"电力新能源/储能/储能赛道的投资逻辑.md","filePath":"电力新能源/储能/储能赛道的投资逻辑.md","lastUpdated":1782213036000}'),n={name:"电力新能源/储能/储能赛道的投资逻辑.md"};function p(s,o,l,i,h,u){return r(),a("div",null,[...o[0]||(o[0]=[e('<h1 id="储能赛道的投资逻辑-从-政策驱动-到-价值驱动-的拐点" tabindex="-1">储能赛道的投资逻辑：从&quot;政策驱动&quot;到&quot;价值驱动&quot;的拐点 <a class="header-anchor" href="#储能赛道的投资逻辑-从-政策驱动-到-价值驱动-的拐点" aria-label="Permalink to &quot;储能赛道的投资逻辑：从&quot;政策驱动&quot;到&quot;价值驱动&quot;的拐点&quot;">​</a></h1><p><strong>2026-06-11 | 陈道雷</strong></p><blockquote><p><em>截至2025年底，中国已投运电力储能项目累计装机规模达到213.3GW——这个数字是三年前的3倍。但真正有意思的不是规模，而是结构变化正在重塑一级市场的投资机会。</em></p></blockquote><hr><h2 id="一、一个奇怪的现象" tabindex="-1">一、一个奇怪的现象 <a class="header-anchor" href="#一、一个奇怪的现象" aria-label="Permalink to &quot;一、一个奇怪的现象&quot;">​</a></h2><p>先讲一个奇怪的事。</p><p>2025年，储能系统报价从年初的0.8元/Wh一路跌到年底的0.5元/Wh，电芯价格更是击穿0.3元/Wh。按常理，价格战这么惨烈，行业应该哀鸿遍野才对。</p><p>但我的判断恰恰相反：<strong>储能赛道一级投资的黄金窗口，刚刚打开。</strong></p><p>为什么？</p><p>因为价格战的本质，是行业从&quot;政策驱动、规模优先&quot;转向**&quot;市场驱动、价值为王&quot;**的阵痛。2026年3月《储能产业研究白皮书2026》的结论印证了这一点：全球储能进入增速换挡、量质齐升的高质量发展阶段。</p><p>驱动逻辑变了，投资逻辑也必须跟着变。</p><hr><h2 id="二、储能市场到底有多大" tabindex="-1">二、储能市场到底有多大？ <a class="header-anchor" href="#二、储能市场到底有多大" aria-label="Permalink to &quot;二、储能市场到底有多大？&quot;">​</a></h2><p>先看三组数字。</p><p><strong>第一组：历史增速。</strong> 截至2025年底，中国已投运电力储能项目累计装机213.3GW。2025年一年新增装机量，超过了2015-2020年五年的总和。这不是线性增长，是J型曲线。</p><p><strong>第二组：未来空间。</strong> 白皮书预判，2030年中国新型储能将成为电力系统核心基础设施。国家能源局2026年4月在ESIE大会上明确表态：加快完善新型储能的市场机制，健全容量电价机制。政策仍在持续加码。</p><p><strong>第三组：结构性机会。</strong> 2025年新增装机中，电源侧配储占比从2023年的70%降到45%，而独立储能和工商业储能占比快速上升。这意味着——储能正在从&quot;新能源的附属品&quot;变成&quot;独立的市场主体&quot;。</p><p>三组数字指向同一个结论：<strong>市场在变大，而且驱动力的结构在根本性变化。</strong></p><hr><h2 id="三、三个层面的投资机会" tabindex="-1">三、三个层面的投资机会 <a class="header-anchor" href="#三、三个层面的投资机会" aria-label="Permalink to &quot;三、三个层面的投资机会&quot;">​</a></h2><p>如果只看储能&quot;赛道&quot;，太粗了。我把它拆成三个层面来看。</p><h3 id="第一层-技术迭代——钠电元年-长时储能破局" tabindex="-1">第一层：技术迭代——钠电元年，长时储能破局 <a class="header-anchor" href="#第一层-技术迭代——钠电元年-长时储能破局" aria-label="Permalink to &quot;第一层：技术迭代——钠电元年，长时储能破局&quot;">​</a></h3><p><strong>钠离子电池是2026年最确定的主题。</strong></p><p>宁德时代2026年官宣钠电池大规模应用，覆盖换电、乘用车、商用车、储能四大领域。这不是实验室新闻，是量产公告。行业数据显示，钠电能量密度已突破200Wh/kg，循环寿命迈向6000次+，成本目标降至0.3元/Wh以下。</p><p>对一级投资来说，关键是<strong>材料端的确定性高于电芯端</strong>：</p><ul><li><strong>硬碳负极</strong>是最具稀缺性的环节。佰思格、天钠科技等正在量产爬坡，克容量&gt;350mAh/g是核心指标。</li><li><strong>电解液/隔膜</strong>的差异化配方也是早期布局窗口。</li></ul><p>钠电电芯层面竞争会很激烈（中科海钠、众钠能源、立方新能源等已获得多轮融资），估值需要谨慎——参考一级市场估值基准，钠电A~C轮PS在8-20x，关键看量产进度和成本曲线。</p><p><strong>液流电池是另一个值得跟的方向。</strong></p><p>大连融科已经Pre-IPO，全钒液流系统成本目前在2-3元/Wh，目标是降至1.5元/Wh以下。长时储能（4h+、8h+）的政策要求正在逐步出台，这个方向的确定性在提高。</p><h3 id="第二层-工商业储能——当前最火的一级赛道" tabindex="-1">第二层：工商业储能——当前最火的一级赛道 <a class="header-anchor" href="#第二层-工商业储能——当前最火的一级赛道" aria-label="Permalink to &quot;第二层：工商业储能——当前最火的一级赛道&quot;">​</a></h3><p>我的判断：<strong>工商业储能是2026-2027年一级市场最值得重仓的方向之一。</strong></p><p>为什么？</p><p>因为商业模式跑通了。工商业储能的收益模型由三部分组成：<strong>峰谷价差套利 + 需求侧响应补贴 + 容量管理</strong>。在浙江、广东、江苏等峰谷价差超过0.7元/kWh的省份，工商业储能IRR已经可以做到8-15%。</p><p>2026年5月智研咨询的报告印证了这一点：政策引导与备电需求增加，行业赛道持续升温。</p><p>这里的一级机会分两类：</p><ol><li><p><strong>运营平台型</strong>（⭐⭐⭐推荐）——有渠道、有运维网络、有数字化能力的工商业储能运营商。弘正储能、奇点能源、绿电荷储等各具特色。关键是看签约项目量和实际运营数据，而不是融资叙事。</p></li><li><p><strong>数字化/AI调度型</strong>（⭐⭐⭐⭐推荐）——这是早期窗口。AI+储能的智能调度可以提升IRR 2-5个百分点。电力现货市场全覆盖后，算法能力就是核心竞争力。</p></li></ol><h3 id="第三层-底层资产证券化——退出的新通道" tabindex="-1">第三层：底层资产证券化——退出的新通道 <a class="header-anchor" href="#第三层-底层资产证券化——退出的新通道" aria-label="Permalink to &quot;第三层：底层资产证券化——退出的新通道&quot;">​</a></h3><p>一个容易被忽视的变化：<strong>储能资产的REITs/ABS通道正在打开。</strong></p><p>这意味着什么？过去一级投储能，退出主要靠IPO或并购。现在有了新的退出路径——把运营成熟的储能电站打包成REITs上市。这会根本性地改变储能资产的估值逻辑：从&quot;赌公司上市&quot;到&quot;算资产现金流&quot;。</p><p>对投资机构来说，这意味着投资策略需要调整：<strong>不仅要会投优质的储能项目公司，还要有能力判断底层资产的现金流质量。</strong></p><hr><h2 id="四、我的判断框架-三句话" tabindex="-1">四、我的判断框架：三句话 <a class="header-anchor" href="#四、我的判断框架-三句话" aria-label="Permalink to &quot;四、我的判断框架：三句话&quot;">​</a></h2><p>说了这么多，归纳成三句话：</p><blockquote><p><strong>第一句：储能正在从&quot;配角&quot;变成&quot;主角&quot;。</strong> 独立储能和工商业储能的占比持续上升，意味着投资要从&quot;跟着政策补贴走&quot;切换到&quot;跟着商业模式走&quot;。</p></blockquote><blockquote><p><strong>第二句：技术路线上，钠电看材料，液流看降本，工商业看运营。</strong> 每个方向的投资逻辑不一样，不能用同一个估值框架去套。</p></blockquote><blockquote><p><strong>第三句：退出的新通道（REITs/ABS）正在改变游戏规则。</strong> 能判断底层资产现金流的机构，会获得结构性优势。</p></blockquote><hr><h2 id="五、对投资人的建议" tabindex="-1">五、对投资人的建议 <a class="header-anchor" href="#五、对投资人的建议" aria-label="Permalink to &quot;五、对投资人的建议&quot;">​</a></h2><ol><li><p><strong>优先看工商业储能运营平台。</strong> 这是当前确定性最高、现金流最好的方向。重点关注签约项目量、实际运营数据、数字化能力——这三个指标比融资轮次更说明问题。</p></li><li><p><strong>钠电材料端（硬碳负极）值得早期布局。</strong> 电芯端竞争太激烈，材料端的稀缺性更高。关注克容量和成本曲线的达标进度。</p></li><li><p><strong>长时储能（液流、压缩空气）可以作为期权配置。</strong> 政策推力的确定性高，但商业化还需要2-3年。适合有耐心、能接受流动性的资金。</p></li><li><p><strong>关注REITs/ABS的政策进展。</strong> 一旦大规模推开，储能资产的估值逻辑会重构。提前建立底层资产评估能力，是差异化的竞争优势。</p></li></ol><hr><h2 id="六、一个需要注意的风险" tabindex="-1">六、一个需要注意的风险 <a class="header-anchor" href="#六、一个需要注意的风险" aria-label="Permalink to &quot;六、一个需要注意的风险&quot;">​</a></h2><p>2025年1月，加州Moss Landing 300MW锂电储能电站火灾——这是全球最大的储能火灾事故之一。安全问题正在成为行业焦点。</p><p>钠电池的安全性优势（热失控风险低）正在被市场重新认识。但对于锂电储能，安全标准的提高意味着成本上升，这会压缩中小型集成商的利润空间。</p><p><strong>投资时一定要问一个问题：这家公司的安全设计是合规成本，还是竞争优势？</strong></p><hr><p><em>以上仅为我个人基于公开信息的分析推演，不构成投资建议。</em></p><hr><p><strong>主要参考：</strong></p><ul><li>《储能产业研究白皮书2026》（中国能源研究会储能专委会/CNESA，2026年3月）</li><li>国家能源局ESIE 2026大会发言（2026年4月）</li><li>宁德时代钠电池大规模应用公告（2026年）</li><li>智研咨询《2026年中国工商业储能行业报告》</li><li>知识库：储能/产业链.md、储能/一级标的库.md、一级市场估值基准.md</li></ul>',59)])])}const d=t(n,[["render",p]]);export{g as __pageData,d as default};
